const sourceItem = $input.first()?.json ?? {};
const triggerSource = sourceItem.triggerSource ?? 'manual';
const triggerLabel = sourceItem.triggerLabel ?? 'Manual run';
return [
  { json: { name: 'apex_http', url: 'http://gimenez.dev/', scheme: 'http', triggerSource, triggerLabel } },
  { json: { name: 'apex_https', url: 'https://gimenez.dev/', scheme: 'https', triggerSource, triggerLabel } },
  { json: { name: 'www_https', url: 'https://www.gimenez.dev/', scheme: 'https', triggerSource, triggerLabel } }
];

const checkedAt = new Date().toISOString();
const targets = $('Build Endpoint Targets').all().map((item) => item.json);
const inputs = $input.all();
const triggerSource = inputs[0]?.json?.triggerSource ?? 'scheduled';
const triggerLabel = inputs[0]?.json?.triggerLabel ?? (triggerSource === 'manual' ? 'Manual run' : 'Scheduled run');

const publicEndpoints = inputs.map((item, index) => {
  const targetIndex = item.pairedItem?.item ?? index;
  const target = targets[targetIndex] || targets[0];
  const bodyText = String(item.json.body || '');
  const locationHeader = item.json.headers?.location || item.json.headers?.Location || null;
  const statusCode = Number(item.json.statusCode || 0);
  const healthy = !item.json.error && statusCode >= 200 && statusCode < 400;

  return {
    name: target.name,
    url: target.url,
    scheme: target.scheme,
    healthy,
    statusCode: item.json.statusCode ?? null,
    statusMessage: item.json.statusMessage ?? null,
    location: locationHeader,
    error: item.json.error ?? null,
    bodyPreview: bodyText.slice(0, 160)
  };
});

const endpointMap = Object.fromEntries(publicEndpoints.map((result) => [result.name, result]));

return [
  {
    json: {
      workflow: 'dns-ssl-guardian',
      checkedAt,
      triggerSource,
      triggerLabel,
      publicEndpoints,
      publicStatus: {
        apexHttpHealthy: Boolean(endpointMap.apex_http?.healthy),
        apexHttpsHealthy: Boolean(endpointMap.apex_https?.healthy),
        wwwHttpsHealthy: Boolean(endpointMap.www_https?.healthy)
      }
    }
  }
];

return [
  { json: { label: 'google_apex_a', resolver: 'google', endpoint: 'https://dns.google/resolve', query: { name: 'gimenez.dev', type: 'A' }, headers: {} } },
  { json: { label: 'google_www_cname', resolver: 'google', endpoint: 'https://dns.google/resolve', query: { name: 'www.gimenez.dev', type: 'CNAME' }, headers: {} } },
  { json: { label: 'cloudflare_apex_a', resolver: 'cloudflare', endpoint: 'https://cloudflare-dns.com/dns-query', query: { name: 'gimenez.dev', type: 'A' }, headers: { accept: 'application/dns-json' } } },
  { json: { label: 'cloudflare_www_cname', resolver: 'cloudflare', endpoint: 'https://cloudflare-dns.com/dns-query', query: { name: 'www.gimenez.dev', type: 'CNAME' }, headers: { accept: 'application/dns-json' } } } 
];

const workflowStaticData = $getWorkflowStaticData('global');
const base = $('Evaluate Endpoint Results').first().json;
const queryItems = $('Build DNS Queries').all().map((item) => item.json);

const dnsResponses = $input.all().map((item, index) => {
  const queryIndex = item.pairedItem?.item ?? index;
  const queryItem = queryItems[queryIndex] || queryItems[0];
  const query = queryItem?.query || {};
  const body = item.json.body || {};
  const answers = Array.isArray(body.Answer) ? body.Answer : [];

  return {
    label: queryItem?.label || null,
    resolver: queryItem?.resolver || null,
    endpoint: queryItem?.endpoint || null,
    query,
    statusCode: item.json.statusCode ?? null,
    statusMessage: item.json.statusMessage ?? null,
    error: item.json.error ?? null,
    answers: answers.map((answer) => String(answer.data || '').replace(/\.$/, '').toLowerCase())
  };
});

const apexRecordsByResolver = Object.fromEntries(
  dnsResponses
    .filter((response) => response.query.name === 'gimenez.dev')
    .map((response) => [response.resolver, response.answers])
);
const wwwTargetsByResolver = Object.fromEntries(
  dnsResponses
    .filter((response) => response.query.name === 'www.gimenez.dev')
    .map((response) => [response.resolver, response.answers])
);

const apexResolverAnswers = Object.values(apexRecordsByResolver);
const wwwResolverAnswers = Object.values(wwwTargetsByResolver);
const apexUnique = [...new Set(apexResolverAnswers.flat())];
const dnsConsistent = apexResolverAnswers.length > 0 && apexResolverAnswers.every((answers) => answers.length > 0) && apexUnique.length === 1;
const wwwPointsToApex = wwwResolverAnswers.length > 0 && wwwResolverAnswers.every((answers) => answers.length > 0 && answers.includes('gimenez.dev'));

const findings = [];
const recommendedActions = [];

if (!dnsConsistent) {
  findings.push('dns_inconsistent_public_resolvers');
  recommendedActions.push('Compare public DNS answers with the registrar and edge configuration.');
}

if (!wwwPointsToApex) {
  findings.push('www_cname_mismatch');
  recommendedActions.push('Ensure the www CNAME points to gimenez.dev.');
}

if (base.publicStatus.apexHttpHealthy && !base.publicStatus.apexHttpsHealthy) {
  findings.push('https_failing_while_http_reachable');
  recommendedActions.push('Check TLS and Google-managed certificate health before changing DNS.');
}

if (base.publicStatus.apexHttpsHealthy && !base.publicStatus.wwwHttpsHealthy) {
  findings.push('www_hostname_coverage_gap');
  recommendedActions.push('Verify the edge certificate covers both apex and www hostnames.');
}

if (!base.publicStatus.apexHttpHealthy && !base.publicStatus.apexHttpsHealthy && dnsConsistent) {
  findings.push('origin_or_edge_unreachable');
  recommendedActions.push('Inspect edge routing and Cloud Run reachability from GCP.');
}

const previousFailures = Number(workflowStaticData.consecutiveFailures || 0);
const consecutiveFailures = findings.length > 0 ? previousFailures + 1 : 0;
const shouldEscalate = findings.length > 0 && consecutiveFailures >= 2;
const summary = findings.length > 0 ? findings.join(', ') : 'dns and tls checks healthy';

workflowStaticData.lastCheckedAt = base.checkedAt;
workflowStaticData.lastSummary = summary;
workflowStaticData.consecutiveFailures = consecutiveFailures;
workflowStaticData.lastStatus = findings.length > 0 ? 'degraded' : 'healthy';

return [
  {
    json: {
      workflow: 'dns-ssl-guardian',
      checkedAt: base.checkedAt,
      triggerSource: base.triggerSource,
      triggerLabel: base.triggerLabel,
      status: findings.length > 0 ? (shouldEscalate ? 'incident' : 'degraded') : 'healthy',
      shouldEscalate,
      consecutiveFailures,
      summary,
      findings,
      recommendedActions,
      publicEndpoints: base.publicEndpoints,
      dnsState: {
        dnsConsistent,
        apexRecordsByResolver,
        apexUnique,
        wwwTargetsByResolver,
        wwwPointsToApex
      },
      dnsResponses
    }
  }
];

const payload = $input.first().json;
const drillMode = $env.CONTROL_PLANE_DRILL === '1';
const shouldNotify = drillMode || payload.triggerSource === 'manual' || payload.status !== 'healthy';
const icon = payload.status === 'healthy'
  ? ':white_check_mark:'
  : payload.status === 'degraded'
    ? ':warning:'
    : ':rotating_light:';
const lines = [
  `${icon} *DNS / SSL Guardian* ${String(payload.status || 'unknown').toUpperCase()}`,
  `Run: ${payload.triggerLabel || payload.triggerSource || 'manual'}`,
  `Checked: ${payload.checkedAt}`,
  `Summary: ${payload.summary}`
];
if (drillMode) {
  lines.push('Mode: control-plane drill');
}
if ((payload.findings || []).length > 0) {
  lines.push(`Findings: ${payload.findings.join(', ')}`);
}
if ((payload.recommendedActions || []).length > 0) {
  lines.push(`Next steps: ${payload.recommendedActions.join(' | ')}`);
}
return [
  {
    json: {
      ...payload,
      slackNotification: {
        skip: !shouldNotify,
        channel: 'C0ALX8C12TG',
        text: lines.join('\n')
      }
    }
  }
];

const payload = $input.first().json;

if (!payload.shouldEscalate) {
  return [{ json: payload }];
}

throw new Error(JSON.stringify({
  workflow: payload.workflow,
  checkedAt: payload.checkedAt,
  consecutiveFailures: payload.consecutiveFailures,
  summary: payload.summary,
  findings: payload.findings,
  recommendedActions: payload.recommendedActions
}));
